import re


def _slugify(text):
    slug = text.lower()
    slug = re.sub(r"[^\w\s-]", "", slug)
    slug = re.sub(r"\s+", "-", slug.strip())
    return slug


def build_toc(markdown):
    lines = []
    seen = {}
    for line in markdown.splitlines():
        if line.startswith("### "):
            level = 3
            text = line[4:].strip()
        elif line.startswith("## "):
            level = 2
            text = line[3:].strip()
        else:
            continue
        base = _slugify(text)
        if base in seen:
            seen[base] += 1
            anchor = f"{base}-{seen[base]}"
        else:
            seen[base] = 0
            anchor = base
        indent = "  " if level == 3 else ""
        lines.append(f"{indent}- [{text}](#{anchor})")
    return "\n".join(lines)
